export function blendedCostPer1k(entry) {
    const per1k = (entry.inputPerM * entry.promptRatio + entry.outputPerM * (1 - entry.promptRatio)) / 1000;
    return parseFloat(per1k.toFixed(4));
}
export function tierLabel(tier) {
    return tier === 'Budget' || tier === 'Mid-Tier' ? 'Economy' : 'Premium';
}
